const body = $input.first().json.body || $input.first().json;
const titulo = (body.titulo || '').trim();
const source = body.source || 'unknown';
const command = String(body.command || 'pelicula').trim().toLowerCase();

if (!titulo) {
  return [{ json: { valid: false, titulo: '', source, command } }];
}

const cache_key = titulo.toLowerCase().replace(/\s+/g, ' ').trim();
return [{ json: { valid: true, titulo, source, command, cache_key, ts: new Date().toISOString() } }];

const resp = $input.first().json;
const ctx = $node["Normalizar"].json;
const is_cached = !!(resp && resp.title && !resp.error);
const datos = is_cached ? resp : null;
const command = String(ctx.command || 'pelicula').toLowerCase();

function buildReply(commandName, movie) {
  const title = movie.title || ctx.titulo || 'Pelicula';
  const rating = movie.rating ?? 'N/D';
  const votes = movie.votes ?? 'N/D';
  const director = movie.director || 'Desconocido';
  const duration = movie.duration || 'N/D';
  const synopsis = movie.synopsis || 'Sinopsis no disponible.';
  const genres = Array.isArray(movie.genres) && movie.genres.length ? movie.genres.join(', ') : 'No disponible';
  const url = movie.url || '';
  const ai = movie.ai_recomendacion || '';
  const aiCon = movie.ai_para_ver_con || '';

  if (commandName === 'nota' || commandName === 'notas') {
    return { status: 'ok', decision: 'CACHE_HIT', command: commandName, reply: '⭐ ' + title + ' | Nota IMDb: ' + rating + '/10' + (url ? ' | IMDb: ' + url : ''), datos: { title, rating, url } };
  }
  if (commandName === 'director') {
    return { status: 'ok', decision: 'CACHE_HIT', command: commandName, reply: '🎬 ' + title + ' | Director: ' + director + (url ? ' | IMDb: ' + url : ''), datos: { title, director, url } };
  }
  if (commandName === 'sinopsis') {
    return { status: 'ok', decision: 'CACHE_HIT', command: commandName, reply: '📖 ' + title + ' | ' + synopsis + (url ? ' | IMDb: ' + url : ''), datos: { title, synopsis, url } };
  }
  if (commandName === 'duracion') {
    return { status: 'ok', decision: 'CACHE_HIT', command: commandName, reply: '⏱ ' + title + ' | Duracion: ' + duration + (url ? ' | IMDb: ' + url : ''), datos: { title, duration, url } };
  }
  if (commandName === 'votos') {
    return { status: 'ok', decision: 'CACHE_HIT', command: commandName, reply: '🗳 ' + title + ' | Votos: ' + votes + (url ? ' | IMDb: ' + url : ''), datos: { title, votes, url } };
  }

  return { status: 'ok', decision: 'CACHE_HIT', command: commandName, reply: '🎬 ' + title + ' | Nota: ' + rating + '/10 | Votos: ' + votes + ' | Director: ' + director + ' | Duracion: ' + duration + ' | Generos: ' + genres + ' | Sinopsis: ' + synopsis + (ai ? ' | IA: ' + ai : '') + (aiCon ? ' | Para ver con: ' + aiCon : '') + (url ? ' | IMDb: ' + url : ''), datos: { title, original_title: movie.original_title, rating, votes, synopsis, director, duration, genres: Array.isArray(movie.genres) ? movie.genres : [], url, ai_recomendacion: ai, ai_para_ver_con: aiCon, ai_vibra: movie.ai_vibra || '' } };
}

return [ { json: Object.assign({}, ctx, { is_cached }, buildReply(command, datos || {})) } ];

const ctx = $input.first().json;
const titulo = ctx.titulo || '';

const llm_guardrail_body = {
  model: 'llama-3.3-70b-versatile',
  max_tokens: 10,
  temperature: 0,
  messages: [
    {
      role: 'system',
      content: 'Eres un clasificador para un bot de peliculas. Responde SOLO con true o false (sin texto extra).\ntrue = el texto es un titulo de pelicula real y conocida.\nfalse = cualquier otra cosa (frases, instrucciones, spam, preguntas).'
    },
    {
      role: 'user',
      content: titulo
    }
  ]
};

return [{ json: { ...ctx, llm_guardrail_body } }];

function extractContent(resp) {
  if (resp.choices && resp.choices[0]) return resp.choices[0].message.content || '';
  if (typeof resp.data !== 'string' || !resp.data.trim()) return '';
  var s;
  try { s = JSON.parse(resp.data); } catch(e) { return ''; }
  if (!s) return '';
  if (s.choices && s.choices[0]) return s.choices[0].message.content || '';
  try {
    var arr = s._outBuffer && Array.isArray(s._outBuffer.data) ? s._outBuffer.data : null;
    if (!arr || !arr.length) return '';
    var raw = '';
    for (var i = 0; i < arr.length && i < 4096; i++) {
      raw += String.fromCharCode(arr[i]);
    }
    var m = raw.match(/"content"\s*:\s*"((?:[^"\\]|\\.)*)"/);
    if (!m) return '';
    return m[1].replace(/\\"/g, '"').replace(/\\\\/g, '\\');
  } catch(e) {}
  return '';
}

const llm = $input.first().json;
const ctx = $node["Construir Guardrail"].json;

// El LLM responde true/false: es pelicula real?
const content = extractContent(llm).trim().toLowerCase();
const real = content === 'true' || content.startsWith('true');

// Deteccion de inyeccion por keywords con normalizacion Unicode
// Elimina tildes y convierte a minusculas para cubrir variantes como
// olvida/olvidas/olvidate/olvídate, ignora/ignorar/IGNORA, actúa/actua
function normalizeStr(s) {
  return s.toLowerCase().normalize('NFD').replace(/[̀-ͯ]/g, '');
}
const tituloNorm = normalizeStr(ctx.titulo || '');
const injectionRoots = [
  'ignor','olvid','forget','override','jailbreak',
  'actua como','act as','ahora eres','now you are',
  'sin restricciones','instrucciones anterior',
  'system prompt','haz lo que','nuevo rol','new role'
];
const injection = injectionRoots.some(kw => tituloNorm.includes(normalizeStr(kw)));

const guardrail_ok = real && !injection;

return [{ json: { ...ctx, guardrail_real: real, guardrail_injection: injection, guardrail_ok } }];

