const scrape = $input.first().json;
const ctx = $node["Normalizar"].json;

if (scrape.error || (!scrape.title && !scrape.titulo)) {
  return [{ json: {
    ...ctx,
    scrape_ok: false,
    movie: null,
    error_msg: scrape.error || 'Pelicula no encontrada en IMDb'
  }}];
}

const title = scrape.title || scrape.titulo || '';
const rating = parseFloat(scrape.rating) || 0;
const synopsis = (scrape.synopsis || '').substring(0, 500);
const director = scrape.director || '';
const genres = Array.isArray(scrape.genres) ? scrape.genres : [];
const votes = parseInt(scrape.votes) || 0;
const duration = scrape.duration || '';
const url = scrape.url || '';
const original_title = scrape.original_title || title;

const prompt = 'Eres un critico de cine experto. Analiza esta pelicula y escribe una recomendacion personal, detallada y unica.\n\nFICHA:\nTitulo: ' + title + '\nDirector: ' + director + '\nRating IMDb: ' + rating + '/10 (' + votes + ' votos)\nGeneros: ' + genres.join(', ') + '\nSinopsis: ' + synopsis + '\n\nINSTRUCCIONES:\n- Cita al menos un detalle concreto de la ficha: un personaje, un giro de trama, el estilo del director o el genero\n- Adapta el tono a la nota: entusiasta si rating >= 7.5, critico si rating < 6, honesto si esta entre 6 y 7.5\n- Nunca empieces igual que otras peliculas, varia el inicio de la frase\n- Maximo 200 caracteres en recomendacion\n- para_ver_con debe reflejar el tono emocional de la pelicula\n\nResponde SOLO con JSON valido sin texto extra:\n{"recomendacion": "texto concreto y variado en espanol, max 200 chars", "para_ver_con": "solo / pareja / amigos / familia", "vibra": "emoji"}';

const llm_body = JSON.stringify({
  model: 'llama-3.3-70b-versatile',
  max_tokens: 400,
  temperature: 0.85,
  messages: [{ role: 'user', content: prompt }]
});

return [{ json: {
  ...ctx,
  scrape_ok: true,
  movie: { title, original_title, rating, votes, synopsis, director, duration, genres, url },
  llm_body
} }];

function extractLLMContent(resp) {
  if (resp.choices && resp.choices[0]) return resp.choices[0].message.content || '';
  if (typeof resp.data !== 'string' || !resp.data.trim()) return '';
  var s;
  try { s = JSON.parse(resp.data); } catch(e) { return ''; }
  if (!s) return '';
  if (s.choices && s.choices[0]) return s.choices[0].message.content || '';
  try {
    var arr = s._outBuffer && Array.isArray(s._outBuffer.data) ? s._outBuffer.data : null;
    if (!arr || !arr.length) return '';
    var raw = '';
    for (var i = 0; i < arr.length && i < 4096; i++) {
      raw += String.fromCharCode(arr[i]);
    }
    var m = raw.match(/"content"\s*:\s*"((?:[^"\\]|\\.)*)"/);
    if (!m) return '';
    return m[1].replace(/\\"/g, '"').replace(/\\\\/g, '\\');
  } catch(e) {}
  return '';
}

const llm = $input.first().json;
const ctx = $node["Procesar Scrape"].json;

if (!ctx.scrape_ok) {
  return [{ json: {
    ...ctx,
    llm_result: { recomendacion: 'No se encontro esta pelicula.', para_ver_con: 'nadie', vibra: '❌' },
    approved: false
  }}];
}



function fallbackRecomendacion(movie) {
  const title = movie && movie.title ? movie.title : 'Esta pelicula';
  const rating = Number(movie && movie.rating ? movie.rating : 0);
  const director = movie && movie.director ? movie.director : '';
  const genreList = movie && Array.isArray(movie.genres) ? movie.genres : [];
  const genre = genreList.length ? genreList[0] : 'cine';
  const idx = title.length % 3;
  if (rating >= 8) {
    const opts = [
      director ? `${director} esta en su mejor version con ${title}, una obra que deja huella.` : `Con ${rating}/10, ${title} es de las que no se olvidan facil.`,
      `${title} justifica cada valoracion: ${genre} a la altura de los grandes.`,
      director ? `Lo que logra ${director} en ${title} es dificil de ignorar: ${genre} de primera.` : `${title} demuestra por que el buen ${genre} sigue siendo necesario.`
    ];
    return opts[idx];
  }
  if (rating >= 6.5) {
    const opts = [
      `Si te gusta el ${genre}, ${title} ofrece lo que promete sin grandes sorpresas.`,
      `${title} no reinventa el ${genre} pero lo ejecuta con oficio${director ? ', firma de ' + director : ''}.`,
      `Un ${rating}/10 que refleja bien ${title}: solida, sin ser imprescindible.`
    ];
    return opts[idx];
  }
  const opts = [
    `${title} tiene sus momentos de ${genre} pero en conjunto no termina de convencer.`,
    `Con un ${rating}/10, ${title} es para fans del ${genre} con paciencia${director ? ' o seguidores de ' + director : ''}.`,
    `Irregular pero no sin interes: ${title} puede sorprender si bajas las expectativas.`
  ];
  return opts[idx];
}

let recomendacion = fallbackRecomendacion(ctx.movie);
let para_ver_con = 'amigos';
let vibra = '🎬';

try {
  const content = extractLLMContent(llm);
  const match = content.match(/\{[\s\S]*?\}/);
  if (match) {
    const p = JSON.parse(match[0]);
    if (p.recomendacion) recomendacion = String(p.recomendacion);
    if (p.para_ver_con) para_ver_con = String(p.para_ver_con);
    if (p.vibra) vibra = String(p.vibra);
  } else if (content && content.trim()) {
    recomendacion = content.replace(/```[\s\S]*?```/g, '').trim().substring(0, 200) || recomendacion;
  }
} catch(e) {}

return [{ json: {
  ...ctx,
  llm_result: { recomendacion, para_ver_con, vibra },
  approved: true
} }];

const d = $input.first().json;
const m = d.movie || {};
const ai = d.llm_result || {};
const command = String(d.command || 'pelicula').toLowerCase();

const datos = {
  title: m.title || d.titulo || 'Pelicula',
  original_title: m.original_title || m.title || d.titulo || 'Pelicula',
  rating: m.rating ?? 0,
  votes: m.votes ?? 0,
  synopsis: m.synopsis || '',
  director: m.director || 'Desconocido',
  duration: m.duration || 'N/D',
  genres: Array.isArray(m.genres) ? m.genres : [],
  url: m.url || '',
  ai_recomendacion: ai.recomendacion || '',
  ai_para_ver_con: ai.para_ver_con || '',
  ai_vibra: ai.vibra || ''
};

function buildReply(commandName, movie) {
  const title = movie.title;
  const rating = movie.rating;
  const votes = movie.votes;
  const director = movie.director || 'Desconocido';
  const duration = movie.duration || 'N/D';
  const synopsis = movie.synopsis || 'Sinopsis no disponible.';
  const genres = Array.isArray(movie.genres) && movie.genres.length ? movie.genres.join(', ') : 'No disponible';
  const url = movie.url || '';

  if (commandName === 'nota' || commandName === 'notas') {
    return { status: 'ok', decision: 'AUTO_APPROVE', command: commandName, reply: '⭐ ' + title + ' | Nota IMDb: ' + rating + '/10' + (url ? ' | IMDb: ' + url : ''), datos: { title, rating, url } };
  }
  if (commandName === 'director') {
    return { status: 'ok', decision: 'AUTO_APPROVE', command: commandName, reply: '🎬 ' + title + ' | Director: ' + director + (url ? ' | IMDb: ' + url : ''), datos: { title, director, url } };
  }
  if (commandName === 'sinopsis') {
    return { status: 'ok', decision: 'AUTO_APPROVE', command: commandName, reply: '📖 ' + title + ' | ' + synopsis + (url ? ' | IMDb: ' + url : ''), datos: { title, synopsis, url } };
  }
  if (commandName === 'duracion') {
    return { status: 'ok', decision: 'AUTO_APPROVE', command: commandName, reply: '⏱ ' + title + ' | Duracion: ' + duration + (url ? ' | IMDb: ' + url : ''), datos: { title, duration, url } };
  }
  if (commandName === 'votos') {
    return { status: 'ok', decision: 'AUTO_APPROVE', command: commandName, reply: '🗳 ' + title + ' | Votos: ' + votes + (url ? ' | IMDb: ' + url : ''), datos: { title, votes, url } };
  }

  return { status: 'ok', decision: 'AUTO_APPROVE', command: commandName, reply: '🎬 ' + title + ' | Nota: ' + rating + '/10 | Votos: ' + votes + ' | Director: ' + director + ' | Duracion: ' + duration + ' | Generos: ' + genres + ' | Sinopsis: ' + synopsis + (ai.recomendacion ? ' | IA: ' + ai.recomendacion : '') + (ai.para_ver_con ? ' | Para ver con: ' + ai.para_ver_con : '') + (url ? ' | IMDb: ' + url : ''), datos };
}

const for_cache = Object.assign({}, datos, { _cache_key: d.cache_key });
const cache_json = JSON.stringify(for_cache);
return [{ json: Object.assign({}, buildReply(command, datos), { for_cache, cache_json }) }];

